## 2. C++ implementation – `blocksci.cpp`

```cpp
/*=====================================================================
  blocksci.cpp – implementation of the C binding declared in blocksci.h
  ---------------------------------------------------------------------
  Design notes
  ---------------------------------------------------------------------
  * The iterator is a thin wrapper around BlockSci’s own iterator
    (`BlockIterator` – see BlockSci source).  The wrapper stores only
    what we need for the hot‑path: a pointer to the underlying iterator,
    a cached max‑height limit, and a reference‑counted handle to the
    global `Chain` object.

  * The callback is called *directly* from the C++ loop – there is no
    `std::function` indirection, no heap allocation and no virtual
    call.  The only extra work per block is a tiny POD copy of the
    fields we expose (`height`, `timestamp`, `tx_count`, `hash`,
    `prev_hash`).

  * The `bs_block_t` struct contains raw pointers to the block’s hash
    data that live inside BlockSci’s internal `Block` object.  Those
    pointers stay valid for the lifetime of the block object, which
    is guaranteed to be at least as long as the callback invocation.
    The C side must **not** free them.

  * The API is deliberately minimal – more elaborate queries can be
    added later without breaking the ABI.

  * The whole file can be compiled as a shared library (`-fPIC`) and
    linked from pure C code.
=====================================================================*/

#include "blocksci.h"
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <memory>
#include <vector>
#include <exception>

/* --------------------------------------------------------------------
   Pull in the real BlockSci headers.  Adjust the include path to match
   your installation.  (The code below assumes the public API lives in
   namespace `blocksci`.)
-------------------------------------------------------------------- */
#include <blocksci/blocksci.hpp>          // <--- real BlockSci header
#include <blocksci/chain/chain.hpp>       // Chain definition
#include <blocksci/chain/block.hpp>       // Block definition

/* --------------------------------------------------------------------
   Internal opaque type – definition hidden from the C side.
-------------------------------------------------------------------- */
struct bs_iter_s {
    /* Shared ownership of the global Chain object.  The Chain is
       constructed elsewhere (e.g. by the BlockSci library) and lives
       for the whole process; we just keep a shared_ptr so that the
       iterator can be destroyed safely even if the user never calls
       `bs_iter_free`. */
    std::shared_ptr<blocksci::Chain> chain;

    /* Current position of the iterator.  Constructed lazily on first
       use so that `bs_iter_new` stays cheap. */
    std::unique_ptr<blocksci::Chain::BlockIterator> it;

    /* Optional stop‑condition – UINT64_MAX means “no limit”. */
    uint64_t max_height = UINT64_MAX;
};

/* --------------------------------------------------------------------
   Helper: translate a BlockSci block into the POD we expose to C.
   The BlockSci `Block` object lives at least until the callback returns,
   so we can safely hand out its internal hash buffers.
-------------------------------------------------------------------- */
static inline void fill_block_pod(const blocksci::Block &src, bs_block_t *dst) {
    dst->height    = src.height();
    dst->timestamp = src.timestamp();
    dst->tx_count  = src.tx_count();

    // BlockSci stores the hash as a `std::array<unsigned char,32>`
    // – we expose the raw pointer.  The memory is owned by `src`.
    dst->hash      = src.hash().data();
    dst->prev_hash = src.prev_hash().data();
}

/* --------------------------------------------------------------------
   Public API implementation
-------------------------------------------------------------------- */

extern "C" {

bs_iter_t *bs_iter_new(void) {
    try {
        // Acquire the global Chain singleton (BlockSci provides it).
        // If the library has not been initialised, this will throw.
        auto chain_ptr = std::make_shared<blocksci::Chain>(blocksci::Chain::get_instance());

        // Allocate our opaque iterator.
        bs_iter_t *handle = static_cast<bs_iter_t*>(std::malloc(sizeof(bs_iter_t)));
        if (!handle) return nullptr;               // out‑of‑memory

        // Placement‑new the struct.
        new (handle) bs_iter_t{std::move(chain_ptr), nullptr, UINT64_MAX};

        return handle;
    } catch (const std::exception &) {
        return nullptr;   // Chain not ready or other fatal error
    }
}

void bs_iter_free(bs_iter_t *it) {
    if (!it) return;
    // Explicitly destroy the object then free the raw memory.
    it->~bs_iter_s();
    std::free(it);
}

/* --------------------------------------------------------------------
   Set a hard stop‑height.  The iterator will stop *before* processing a
   block whose height > max_height.  This is cheap – just a store.
-------------------------------------------------------------------- */
void bs_iter_set_max_height(bs_iter_t *it, uint64_t max_height) {
    if (!it) return;
    it->max_height = max_height;
}

/* --------------------------------------------------------------------
   Walk the chain, invoking the user callback for each block.
   The loop is deliberately written in straight‑line C++ with no virtual
   calls or std::function indirection – this is the hot path.
-------------------------------------------------------------------- */
int bs_iter_foreach(bs_iter_t *handle, bs_block_cb_t cb, void *user_data) {
    if (!handle || !cb) return -1;

    // Lazily create the underlying BlockIterator on first use.
    if (!handle->it) {
        try {
            handle->it = std::make_unique<blocksci::Chain::BlockIterator>(handle->chain->begin());
        } catch (const std::exception &) {
            return -1;
        }
    }

    // Local copy for speed.
    auto &it = *handle->it;
    const uint64_t max_h = handle->max_height;

    // Re‑use a single POD struct to avoid per‑iteration allocation.
    bs_block_t pod {};

    for (; it != handle->chain->end(); ++it) {
        const blocksci::Block &blk = *it;
        if (blk.height() > max_h) break;   // early‑out if limit reached

        fill_block_pod(blk, &pod);

        // Call the user function.  If it returns non‑zero we abort.
        int rc = cb(user_data, &pod);
        if (rc != 0) return rc;
    }

    return 0;   // walked everything without abort
}

} // extern "C"
```

